import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Allocate memory dynamically based on input length
        char[] buffer = new char[name.length()];

        // Copy characters from input to buffer with bounds checking
        for (int i = 0; i < name.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = name.charAt(i);
            } else {
                break; // Break loop if input exceeds allocated buffer size
            }
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
